# Too much packed in -> a loop is clearer
out = [transform(x) for sub in data for x in sub if x and check(x)]

# When it gets this dense, unfold it:
out = []
for sub in data:
    for x in sub:
        if x and check(x):
            out.append(transform(x))

data = [n * 2 for n in range(3)]
print(data)              # [0, 2, 4]

try:
    print(n)             # n was scoped to the comprehension
except NameError as e:
    print("leaked?", e)  # name 'n' is not defined

names = ["ada", "bob", "cy"]

# build: name -> length
lengths = {name: len(name) for name in names}
print(lengths)           # {'ada': 3, 'bob': 3, 'cy': 2}

# invert an existing dict: value -> key
codes = {"red": 1, "green": 2}
flipped = {v: k for k, v in codes.items()}
print(flipped)           # {1: 'red', 2: 'green'}

pairs = [("a", 1), ("b", 2), ("a", 3)]

# A comprehension CAN'T accumulate groups cleanly:
# {k: v for k, v in pairs} -> {'a': 3, 'b': 2}  (last wins!)

groups = {}
for k, v in pairs:
    groups.setdefault(k, []).append(v)
print(groups)            # {'a': [1, 3], 'b': [2]}

# DON'T: nobody can read this at a glance
out = [g(x) for grp in data for x in grp if x > 0 if h(x)]

# DO: a loop is clearer and debuggable
out = []
for grp in data:
    for x in grp:
        if x > 0 and h(x):
            out.append(g(x))
